    if (tileOuter > outputLength) tileOuter = outputLength;
    // Align down to ALIGN_ELEMS? Not necessary since output is int64.
    // But to avoid too fine grained tiling, keep as is.

    // BlockDim: try to use number of output elements if small, else cap.
    uint32_t blockDim = CeilDiv(outputLength, tileOuter);
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;

    context->SetBlockDim(blockDim);

